opencat.script:
// ── orbs: entry stagger ────────────────────────────────────────
var ids = ['orb-1','orb-2','orb-3','orb-4','orb-5','orb-6','orb-7'];
var faceIds = ['orb-1-face','orb-2-face','orb-3-face','orb-4-face','orb-5-face','orb-6-face','orb-7-face'];
var labelIds = ['orb-1-tag','orb-2-tag','orb-3-tag','orb-4-tag','orb-5-tag','orb-6-tag','orb-7-tag'];

ctx.fromTo(ids, {opacity:0, scale:0.42, y:90}, {opacity:1, scale:1, y:0, duration:1.4, stagger:0.266667, ease:'spring.wobbly'});

// ── orbs: drift + color + face + label loops ───────────────────
var orbCfg = [
  {tx0:-10,tx1:12,ty0:-14,ty1:10,sc0:0.98,sc1:1.04,rot0:-4,rot1:3,dur:2.933333,del:0,c0:'#facc15',c1:'#fb7185'},
  {tx0:-12,tx1:10,ty0:-18,ty1:14,sc0:0.95,sc1:1.06,rot0:-3,rot1:4,dur:3.2,del:0.166667,c0:'#22c55e',c1:'#4ade80'},
  {tx0:-8,tx1:14,ty0:-12,ty1:8,sc0:0.97,sc1:1.05,rot0:-5,rot1:5,dur:2.733333,del:0.3,c0:'#38bdf8',c1:'#60a5fa'},
  {tx0:-14,tx1:12,ty0:-16,ty1:12,sc0:0.96,sc1:1.05,rot0:-4,rot1:4,dur:3.066667,del:0.4,c0:'#fb7185',c1:'#f43f5e'},
  {tx0:-10,tx1:16,ty0:-12,ty1:14,sc0:0.95,sc1:1.07,rot0:-3,rot1:5,dur:3.266667,del:0.533333,c0:'#a855f7',c1:'#c084fc'},
  {tx0:-12,tx1:10,ty0:-14,ty1:10,sc0:0.97,sc1:1.04,rot0:-5,rot1:4,dur:2.866667,del:0.666667,c0:'#fb923c',c1:'#fdba74'},
  {tx0:-8,tx1:12,ty0:-16,ty1:12,sc0:0.96,sc1:1.05,rot0:-4,rot1:4,dur:3,del:0.8,c0:'#14b8a6',c1:'#2dd4bf'}
];
for (var i = 0; i < ids.length; i++) {
  var c = orbCfg[i];
  ctx.fromTo(ids[i], {x:c.tx0, y:c.ty0, scale:c.sc0, rotate:c.rot0}, {x:c.tx1, y:c.ty1, scale:c.sc1, rotate:c.rot1, duration:c.dur, delay:c.del, ease:'ease-in-out', repeat:-1, yoyo:true});
  ctx.fromTo(ids[i], {bg:c.c0}, {bg:c.c1, duration:c.dur+0.6, delay:c.del, ease:'ease-in-out', repeat:-1, yoyo:true});
  ctx.fromTo(faceIds[i], {y:-3, rotate:-1}, {y:5, rotate:2, duration:1.8+i*0.133333, delay:i*0.1, ease:'ease-in-out', repeat:-1, yoyo:true});
  ctx.fromTo(labelIds[i], {scale:0.96, opacity:0.75}, {scale:1.06, opacity:1, duration:1.533333+i*0.1, delay:i*0.066667, ease:'ease-in-out', repeat:-1, yoyo:true});
}

// ── left copy entrance ─────────────────────────────────────────
ctx.fromTo(['left-kicker','left-title-1','left-title-2','left-body','left-pill-row'], {opacity:0, y:24}, {opacity:1, y:0, stagger:0.2, duration:0.8, ease:'spring.gentle'});
